#ifndef RFID_H
#define RFID_H
#include <MFRC522.h>
void rfid_setup();
void rfid_loop();
bool rfid_card_present();
String rfid_get_uid();
typedef void (*rfid_cb)(const char* uid);
void rfid_on_scan(rfid_cb cb);
#endif

firmware_template.source:
#include "rfid_rc522.h"
#include <SPI.h>
static MFRC522 rfid(5,27);
static rfid_cb _cb=nullptr;static String _uid="";
void rfid_setup(){SPI.begin();rfid.PCD_Init();Serial.println("[rfid] OK");}
void rfid_loop(){
  if(!rfid.PICC_IsNewCardPresent()||!rfid.PICC_ReadCardSerial())return;
  _uid="";for(byte i=0;i<rfid.uid.size;i++){if(rfid.uid.uidByte[i]<0x10)_uid+="0";_uid+=String(rfid.uid.uidByte[i],HEX);}
  _uid.toUpperCase();Serial.printf("[rfid] UID: %s\n",_uid.c_str());
  if(_cb)_cb(_uid.c_str());rfid.PICC_HaltA();
}
bool rfid_card_present(){return rfid.PICC_IsNewCardPresent();}
String rfid_get_uid(){return _uid;}
void rfid_on_scan(rfid_cb cb){_cb=cb;}
